export function matchDiseases(symptomsText) {
  if (!symptomsText || symptomsText.trim().length === 0) return [];
  
  const userSymptoms = symptomsText.toLowerCase()
    .split(/[,;]+/)
    .map(s => s.trim())
    .filter(s => s.length > 2);

  if (userSymptoms.length === 0) return [];

  const scored = diseaseDatabase.map(disease => {
    let matchCount = 0;
    let matchedSymptoms = [];

    disease.symptoms.forEach(symptom => {
      const symptomWords = symptom.toLowerCase().split(" ");
      const matched = userSymptoms.some(us =>
        symptomWords.some(word => word.length > 3 && (us.includes(word) || word.includes(us)))
      );
      if (matched) {
        matchCount++;
        matchedSymptoms.push(symptom);
      }
    });

    const confidencePercent = Math.min(95, Math.round((matchCount / Math.max(disease.symptoms.length, 1)) * 100 * 1.5));
    const confidence = confidencePercent > 60 ? "High" : confidencePercent > 30 ? "Medium" : "Low";

    return {
      ...disease,
      matchCount,
      matchedSymptoms,
      confidencePercent,
      confidence,
    };
  });

  return scored
    .filter(d => d.matchCount >= 2)
    .sort((a, b) => b.matchCount - a.matchCount)
    .slice(0, 5);
}

export default diseaseDatabase;